class Playground {
    async run(inputs) {
        const inputStr = inputs[0] || '10, 5, 30, 2, 8, 15, 1';
        const vals = inputStr.split(',').map(v => parseInt(v.trim())).filter(n => !isNaN(n));

        this.log('Building Max Heap from input...');
        this.heap.init(vals, 'max');
        this.sorted.init([]);
        await this.await();

        this.log('Pushing value 50...');
        this.heap.push(50);
        await this.await();

        this.log('Pushing value 12...');
        this.heap.push(12);
        await this.await();

        this.log('Starting Heap Sort (Extract Max)...');
        const sortedArr = [];
        while (true) {
            const max = this.heap.pop();
            if (max === null) break;

            this.log(`Extracted Max: ${max}`);
            sortedArr.push(max);
            this.sorted.push(max);
            await this.await();
        }

        this.log('Heap Sort Complete!');
    }
}
